// Smart filter: identify Super-Agent automated emails.
// ALWAYS preserve Anthropic authentication emails.
// Only soft-delete emails that are clearly from the super-agent system.

const ANTHROPIC_AUTH_PATTERNS = [
  /anthropic/i,
  /claude\.ai/i,
  /verification.*code/i,
  /sign.*in.*code/i,
  /magic.*link/i,
  /your.*login/i,
  /confirm.*email/i
];

const SUPER_AGENT_SUBJECT_PATTERNS = [
  /chief of staff briefing/i,
  /chief of staff.*alert/i,
  /system alert.*workflow/i,
  /workflow.*failure/i,
  /morning briefing.*super.?agent/i,
  /super.?agent.*briefing/i,
  /\[critical\].*workflow/i,
  /\[high\].*workflow/i,
  /\[medium\].*workflow/i,
  /\[low\].*workflow/i,
  /n8n.*execution.*error/i,
  /auto.?heal.*workflow/i,
  /health.*monitor.*super/i,
  /nightly.*review.*super/i,
  /weekly.*review.*super/i,
  /railway.*deployment/i,
  /railway.*build.*failed/i,
  /railway.*service.*down/i
];

const SUPER_AGENT_SENDER_PATTERNS = [
  /@railway\.app/i,
  /noreply@railway/i,
  /notifications@railway/i,
  /no-reply@railway/i,
  /super-agent-production/i
];

const items = $input.all();
const toSoftDelete = [];

for (const it of items) {
  const msg = it.json;
  const subject = msg.subject || '';
  const senderAddr = (msg.from && msg.from.emailAddress && msg.from.emailAddress.address) || '';
  const senderName = (msg.from && msg.from.emailAddress && msg.from.emailAddress.name) || '';
  const messageId = msg.id;

  if (!messageId) continue;

  // Skip emails less than 30 minutes old — give delivery time.
  const recv = new Date(msg.receivedDateTime || msg.createdDateTime || 0);
  if (Date.now() - recv.getTime() < 30 * 60 * 1000) continue;

  // HARD RULE: Never touch Anthropic authentication emails.
  const isAuthEmail = ANTHROPIC_AUTH_PATTERNS.some(p => p.test(subject) || p.test(senderAddr) || p.test(senderName));
  if (isAuthEmail) continue;

  // Check if this looks like a super-agent automated email.
  const matchesSubject = SUPER_AGENT_SUBJECT_PATTERNS.some(p => p.test(subject));
  const matchesSender = SUPER_AGENT_SENDER_PATTERNS.some(p => p.test(senderAddr) || p.test(senderName));

  if (matchesSubject || matchesSender) {
    toSoftDelete.push({
      json: {
        messageId,
        subject,
        sender: senderAddr,
        receivedAt: msg.receivedDateTime,
        reason: matchesSubject ? 'super_agent_subject' : 'super_agent_sender'
      }
    });
  }
}

return toSoftDelete;
